class Solution {
public:
    bool canPartition(vector<int>& nums) {
        int s=accumulate(nums.begin(),nums.end(),0);
        if(s&1) return false;
        int t=s/2; vector<char> dp(t+1); dp[0]=1;
        for(int x:nums)
            for(int j=t;j>=x;j--) dp[j]|=dp[j-x];
        return dp[t];
    }
};

