bool canPartition(int* nums, int n) {
    long s=0; for(int i=0;i<n;i++) s+=nums[i];
    if(s&1) return false;
    int t=(int)(s/2);
    char* dp=calloc(t+1,1); dp[0]=1;
    for(int i=0;i<n;i++) for(int j=t;j>=nums[i];j--) dp[j]|=dp[j-nums[i]];
    bool ok=dp[t]; free(dp); return ok;
}
